21	const BASE_PREMIUMS: Record<string, number> = {
22	  sword: 100,
23	  amulet: 60,
24	  staff: 80,
25	  potion: 40,
26	  rune: 25,
27	  moonstone: 25,
28	};
29	
30	const PROCESSING_FEE_G = 5;
31	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1; // 10% surcharge on policy base
32	const COMPONENT_BLOCK_SIZE = 3;
33	const COMPONENT_BLOCK_PRICE_G = 60;
34	const CURSE_SURCHARGE_RATE = 0.5; // 50% of cursed item's base premium
35	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3; // 30% of enchanted item's base premium
36	const HIGH_ENCHANTMENT_THRESHOLD = 5;
37	
38	const COMPONENT_TYPES = ["rune", "moonstone"];
39	
40	const priceForComponentGroup = (count: number, unitPrice: number): number =>
41	  count === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE_G : count * unitPrice;
42	
43	const isComponent = (item: Item): boolean => COMPONENT_TYPES.includes(item.type);
44	
45	const isCursed = (item: Item): boolean => item.cursed === true;
46	const isHighlyEnchanted = (item: Item): boolean =>
47	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
48	
49	const surchargeFor = (items: Item[], predicate: (i: Item) => boolean, rate: number): number =>
50	  items.filter(predicate).reduce((sum, item) => sum + BASE_PREMIUMS[item.type] * rate, 0);
51	
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	const LOYALTY_DISCOUNT_RATE = 0.2; // 20% discount on policy base
54	const FOLLOW_UP_CONTRACT_DISCOUNT_RATE = 0.15; // 15% discount on policy base for contracts after the first
55	
56	const isLoyalCustomer = (customer: Customer): boolean =>
57	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
58	
59	const quotePremium = (items: Item[], customer: Customer, isFollowUpContract: boolean): number => {
60	  const componentBase = COMPONENT_TYPES.reduce((sum, type) => {
61	    const count = items.filter((i) => i.type === type).length;
62	    return sum + priceForComponentGroup(count, BASE_PREMIUMS[type]);
63	  }, 0);
64	  const otherItemsBase = items
65	    .filter((i) => !isComponent(i))
66	    .reduce((sum, item) => sum + BASE_PREMIUMS[item.type], 0);
67	  const policyBase = otherItemsBase + componentBase;
68	  const curseSurcharge = surchargeFor(items, isCursed, CURSE_SURCHARGE_RATE);
69	  const enchantmentSurcharge = surchargeFor(items, isHighlyEnchanted, HIGH_ENCHANTMENT_SURCHARGE_RATE);
70	  const firstInsuranceSurcharge = policyBase * FIRST_INSURANCE_SURCHARGE_RATE;
71	  const loyaltyDiscount = isLoyalCustomer(customer) ? policyBase * LOYALTY_DISCOUNT_RATE : 0;
72	  const followUpDiscount = isFollowUpContract ? policyBase * FOLLOW_UP_CONTRACT_DISCOUNT_RATE : 0;
73	  return Math.ceil(
74	    policyBase +
75	      curseSurcharge +
76	      enchantmentSurcharge +
77	      firstInsuranceSurcharge -
78	      loyaltyDiscount -
79	      followUpDiscount +
80	      PROCESSING_FEE_G,
81	  );
82	};
83	
84	export const processScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => {
85	  const results = scenario.steps.map((step, index) => ({
86	    premium: quotePremium(step.items, scenario.customer, index > 0),
87	  }));
88	  return { results };
89	};
